const threshold = Number(base.retrieval_score_threshold ?? 0.55);
const minResultCount = Number(base.min_result_count ?? 3);
const candidates = Array.isArray(raw) ? raw.map((hit, i) => {
  const p = hit.payload || {};
  return {
    qdrant_point_id: String(hit.id),
    rank: i + 1,
    retrieval_score: Number(hit.score || 0),
    channel_id: p.channel_id || '',
    channel_name: p.channel || '',
    thread_name: p.thread_name || '',
    first_message_id: p.first_message_id || '',
    message_ids: Array.isArray(p.message_ids) ? p.message_ids.map(String) : [],
    start_ts: p.start_ts || null,
    end_ts: p.end_ts || null,
    text: p.text || '',
    payload: p
  };
}) : [];
const passed = candidates
  .filter(c => c.retrieval_score >= threshold)
  .sort((a, b) => b.retrieval_score - a.retrieval_score);
let stage1GateReason = 'stage_1_retrieval_passed';
let stage1GateStatus = 'passed';
let refusalReason = null;
if (!base.embedding_ok) {
  stage1GateStatus = 'refused';
  stage1GateReason = 'query_embedding_failed';
  refusalReason = 'query_embedding_failed';
} else if (statusCode < 200 || statusCode >= 300) {
  stage1GateStatus = 'refused';
  stage1GateReason = 'qdrant_query_failed';
  refusalReason = 'qdrant_query_failed';
} else if (candidates.length === 0) {
  stage1GateStatus = 'refused';
  stage1GateReason = 'no_qdrant_results';
  refusalReason = 'no_qdrant_results';
} else if (passed.length < minResultCount) {
  stage1GateStatus = 'refused';
  stage1GateReason = 'fewer_than_min_stage_1_results';
  refusalReason = 'fewer_than_min_stage_1_results';
}
return [{ json: {
  ...base,
  qdrant_completed_ms: now,
  qdrant_latency_ms: Math.max(0, now - base.qdrant_started_ms),
  qdrant_status_code: statusCode,
  raw_candidate_count: candidates.length,
  passed_candidate_count: passed.length,
  candidates,
  passed_stage_1_candidates: passed,
  stage_1_gate_status: stage1GateStatus,
  stage_1_gate_reason: stage1GateReason,
  stage_1_gate_threshold: threshold,
  stage_1_gate_min_result_count: minResultCount,
  should_continue_to_context: stage1GateStatus === 'passed',
  refusal_reason: refusalReason,
  retrieval_status: stage1GateStatus === 'passed' ? 'stage_1_context_candidates_found' : 'no_context',
  final_status: stage1GateStatus === 'passed' ? 'retrieving' : 'refused'
}}];

const state = $items('Build Stage 1 Retrieval Gate')[0].json;
const candidates = (state.passed_stage_1_candidates || []).map(candidate => ({
  id: candidate.qdrant_point_id,
  text: candidate.text,
  metadata: {
    qdrant_point_id: candidate.qdrant_point_id,
    rank: candidate.rank,
    retrieval_score: candidate.retrieval_score,
    channel_id: candidate.channel_id,
    channel_name: candidate.channel_name,
    thread_name: candidate.thread_name,
    first_message_id: candidate.first_message_id,
    message_ids: candidate.message_ids,
    start_ts: candidate.start_ts,
    end_ts: candidate.end_ts
  }
}));
return [{ json: { ...state, reranker_started_ms: Date.now(), reranker_request_candidate_count: candidates.length, reranker_request: { query: state.user_query, candidates } } }];
